import{_ as t,o,c as a,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Deploy on Northflank","description":"","frontmatter":{"title":"Deploy on Northflank"},"headers":[],"relativePath":"install/northflank.md","filePath":"install/northflank.md","lastUpdated":1771906665000}'),n={name:"install/northflank.md"};function r(i,e,s,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[l('<p>Deploy OpenSoul on Northflank with a one-click template and finish setup in your browser. This is the easiest “no terminal on the server” path: Northflank runs the Gateway for you, and you configure everything via the <code>/setup</code> web wizard.</p><h2 id="how-to-get-started" tabindex="-1"><a class="header-anchor" href="#how-to-get-started">#</a> How to get started</h2><ol><li>Click <a href="https://northflank.com/stacks/deploy-opensoul" target="_blank" rel="noreferrer">Deploy OpenSoul</a> to open the template.</li><li>Create an <a href="https://app.northflank.com/signup" target="_blank" rel="noreferrer">account on Northflank</a> if you don’t already have one.</li><li>Click <strong>Deploy OpenSoul now</strong>.</li><li>Set the required environment variable: <code>SETUP_PASSWORD</code>.</li><li>Click <strong>Deploy stack</strong> to build and run the OpenSoul template.</li><li>Wait for the deployment to complete, then click <strong>View resources</strong>.</li><li>Open the OpenSoul service.</li><li>Open the public OpenSoul URL and complete setup at <code>/setup</code>.</li><li>Open the Control UI at <code>/opensoul</code>.</li></ol><h2 id="what-you-get" tabindex="-1"><a class="header-anchor" href="#what-you-get">#</a> What you get</h2><ul><li>Hosted OpenSoul Gateway + Control UI</li><li>Web setup wizard at <code>/setup</code> (no terminal commands)</li><li>Persistent storage via Northflank Volume (<code>/data</code>) so config/credentials/workspace survive redeploys</li></ul><h2 id="setup-flow" tabindex="-1"><a class="header-anchor" href="#setup-flow">#</a> Setup flow</h2><ol><li>Visit <code>https://&lt;your-northflank-domain&gt;/setup</code> and enter your <code>SETUP_PASSWORD</code>.</li><li>Choose a model/auth provider and paste your key.</li><li>(Optional) Add Telegram/Discord/Slack tokens.</li><li>Click <strong>Run setup</strong>.</li><li>Open the Control UI at <code>https://&lt;your-northflank-domain&gt;/opensoul</code></li></ol><p>If Telegram DMs are set to pairing, the setup wizard can approve the pairing code.</p><h2 id="getting-chat-tokens" tabindex="-1"><a class="header-anchor" href="#getting-chat-tokens">#</a> Getting chat tokens</h2><h3 id="telegram-bot-token" tabindex="-1"><a class="header-anchor" href="#telegram-bot-token">#</a> Telegram bot token</h3><ol><li>Message <code>@BotFather</code> in Telegram</li><li>Run <code>/newbot</code></li><li>Copy the token (looks like <code>123456789:AA...</code>)</li><li>Paste it into <code>/setup</code></li></ol><h3 id="discord-bot-token" tabindex="-1"><a class="header-anchor" href="#discord-bot-token">#</a> Discord bot token</h3><ol><li>Go to <a href="https://discord.com/developers/applications" target="_blank" rel="noreferrer">https://discord.com/developers/applications</a></li><li><strong>New Application</strong> → choose a name</li><li><strong>Bot</strong> → <strong>Add Bot</strong></li><li><strong>Enable MESSAGE CONTENT INTENT</strong> under Bot → Privileged Gateway Intents (required or the bot will crash on startup)</li><li>Copy the <strong>Bot Token</strong> and paste into <code>/setup</code></li><li>Invite the bot to your server (OAuth2 URL Generator; scopes: <code>bot</code>, <code>applications.commands</code>)</li></ol>',13)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
